const state={bootstrap:null,tracks:[],currentMode:'same',requestFilter:'all',pendingLiveTags:null,workspaceMode:localStorage.getItem('kr_desk_mode')||'regia',libraryExtraFilters:{}};
const $=(selector,root=document)=>root.querySelector(selector);
const $$=(selector,root=document)=>[...root.querySelectorAll(selector)];
const api=async(action,options={})=>{const response=await fetch(`api.php?action=${action}`,{cache:'no-store',...options});const text=await response.text();let data=null;try{data=text?JSON.parse(text):null}catch(error){throw new Error(`Risposta API non valida (${response.status}): ${text.slice(0,180)||'vuota'}`)}if(!data)throw new Error(`Risposta API vuota (${response.status})`);if(!response.ok||data.error)throw new Error(data.error||'Errore inatteso');return data};
const post=(action,data)=>api(action,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(data)});
const escapeHtml=value=>String(value??'').replace(/[&<>'"]/g,char=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#039;','"':'&quot;'}[char]));
const formatDuration=seconds=>seconds?`${Math.floor(seconds/60)}:${String(seconds%60).padStart(2,'0')}`:'-';
const scaleMode=track=>{if(track?.spotify_mode!==null&&track?.spotify_mode!==undefined&&track?.spotify_mode!=='')return Number(track.spotify_mode)===1?String.fromCodePoint(0x1F642):String.fromCodePoint(0x1F641);const camelot=String(track?.camelot||'').trim().toUpperCase();if(/^[0-9]{1,2}[AB]$/.test(camelot))return camelot.endsWith('B')?String.fromCodePoint(0x1F642):String.fromCodePoint(0x1F641);const key=String(track?.musical_key||'').trim();return key?(/m$/i.test(key)?String.fromCodePoint(0x1F641):String.fromCodePoint(0x1F642)):'-'};
const toast=message=>{const element=$('#app-toast');element.textContent=message;element.classList.add('show');setTimeout(()=>element.classList.remove('show'),2600)};
const krProgress=(()=>{let hideTimer=null;function element(){let box=$('#global-progress');if(box)return box;box=document.createElement('div');box.id='global-progress';box.className='global-progress';box.innerHTML='<div class="global-progress-head"><strong></strong><span></span></div><div class="global-progress-bar"><i></i></div><small></small>';document.body.append(box);return box}function set(label,current=0,total=0,detail=''){const box=element(),percent=total?Math.max(0,Math.min(100,Math.round(current/total*100))):0;clearTimeout(hideTimer);box.classList.add('show');box.classList.toggle('indeterminate',!total);$('strong',box).textContent=label;$('span',box).textContent=total?`${current}/${total} - ${percent}%`:'';$('small',box).textContent=detail||'';$('.global-progress-bar i',box).style.width=total?`${percent}%`:'35%'}return{start:(label,total=0,detail='')=>set(label,0,total,detail),update:set,done:(label='Operazione completata',detail='')=>{const box=element();box.classList.remove('indeterminate');box.classList.add('show');$('strong',box).textContent=label;$('span',box).textContent='100%';$('small',box).textContent=detail;$('.global-progress-bar i',box).style.width='100%';clearTimeout(hideTimer);hideTimer=setTimeout(()=>box.classList.remove('show'),1800)},fail:(label='Operazione interrotta',detail='')=>{const box=element();box.classList.remove('indeterminate');box.classList.add('show');$('strong',box).textContent=label;$('span',box).textContent='';$('small',box).textContent=detail;$('.global-progress-bar i',box).style.width='100%';clearTimeout(hideTimer);hideTimer=setTimeout(()=>box.classList.remove('show'),2600)}}})();window.krProgress=krProgress;
const viewModes={dashboard:'regia',requests:'regia',quiz:'regia',suggestions:'regia','studio-dashboard':'studio',library:'studio',playlists:'studio',spotify:'studio',duplicates:'studio',analysis:'studio',settings:'studio'};
const modeDefaults={regia:'dashboard',studio:'studio-dashboard'};
function setDeskMode(mode,{navigate=true}={}){mode=mode==='studio'?'studio':'regia';state.workspaceMode=mode;localStorage.setItem('kr_desk_mode',mode);document.body.dataset.deskMode=mode;$$('[data-desk-mode]').forEach(button=>button.classList.toggle('active',button.dataset.deskMode===mode));$$('#main-nav .nav-item').forEach(item=>item.classList.toggle('mode-hidden',item.dataset.mode!==mode));const active=$('.view.active')?.id?.replace('view-','')||'';if(navigate&&viewModes[active]!==mode)showView(modeDefaults[mode])}
const showView=name=>{name=name||modeDefaults[state.workspaceMode]||'dashboard';const targetMode=viewModes[name]||state.workspaceMode||'regia';if(targetMode!==state.workspaceMode)setDeskMode(targetMode,{navigate:false});$$('.view').forEach(view=>view.classList.toggle('active',view.id===`view-${name}`));$$('.nav-item').forEach(item=>item.classList.toggle('active',item.dataset.view===name));const titles={dashboard:'Live desk',requests:'Richieste pubblico',quiz:'Quiz Live',suggestions:'Prossimo brano','studio-dashboard':'Dashboard Studio',library:'Ricerca libreria',playlists:'Playlist',spotify:'Import / Export',duplicates:'Qualita / Doppioni',analysis:'Analisi',settings:'Configurazione'};$('#view-title').textContent=titles[name]||'KR Desk';$('#eyebrow').textContent=targetMode==='regia'?'MODALITA REGIA':'MODALITA STUDIO';location.hash=name;$('.sidebar').classList.remove('open');if(name==='studio-dashboard'&&typeof loadStudioDashboard==='function')loadStudioDashboard();if(name==='library'&&!state.tracks.length)loadTracks();if(name==='suggestions')loadSuggestions();if(name==='duplicates')loadDuplicateFolders().then(loadDuplicates);if(name==='requests')loadRequests();if(name==='quiz'&&typeof loadQuizControl==='function')loadQuizControl();if(name==='analysis'&&typeof loadLibraryAnalysis==='function')loadLibraryAnalysis();if(name==='playlists'&&typeof loadPlaylists==='function')loadPlaylists()};

async function boot(){state.bootstrap=await api('bootstrap');setDeskMode(state.workspaceMode,{navigate:false});renderDashboard();fillSettings();await loadTracks(true);setInterval(updateClock,1000);setInterval(refreshLiveCard,10000);setInterval(refreshAutomixEstimates,60000);updateClock()}
async function refreshAutomixEstimates(){try{await api('request-estimates-refresh');if(document.body.contains($('#view-requests'))&&$('#view-requests').classList.contains('active'))await loadRequests();}catch(error){}}
function renderDashboard(refreshRequests=true){const data=state.bootstrap;$('#library-count').textContent=`${data.stats.tracks} brani indicizzati`;$('#request-badge').textContent=data.stats.requests;$('#new-requests').textContent=data.stats.requests;$('#played-count').textContent=data.stats.played_today;$('#dup-count').textContent=data.stats.duplicates;renderCurrent(data.current);$('#recent-tracks').innerHTML=data.recent.length?data.recent.map((track,index)=>`<div class="compact-row"><span class="number">${String(index+1).padStart(2,'0')}</span><div><strong>${escapeHtml(track.artist)} - ${escapeHtml(track.title)}</strong><small>${escapeHtml(track.genre||'-')} | ${track.bpm??'-'} BPM | ${escapeHtml(track.camelot||track.musical_key||'-')}</small></div><span class="time">${track.played_at?new Date(track.played_at.replace(' ','T')).toLocaleTimeString('it-IT',{hour:'2-digit',minute:'2-digit'}):'-'}</span></div>`).join(''):'<div class="empty-state">Nessun brano nella cronologia VirtualDJ</div>';if(refreshRequests)loadDashboardRequests()}

async function loadStudioDashboard(){
  const cards=$('#studio-summary-cards');
  if(!cards)return;
  const stats=state.bootstrap?.stats||{};
  let databaseItems=[],marked=[],approved=[],scan=null,issues=null;
  try{databaseItems=(await api('database-status')).items||[]}catch(error){}
  try{marked=(await api('deletion-candidates&status=marked')).items||[]}catch(error){}
  try{approved=(await api('deletion-candidates&status=approved')).items||[]}catch(error){}
  try{scan=(await api('e-duplicates-status')).scan||null}catch(error){}
  try{issues=(await api('studio-issues')).items||null}catch(error){}
  databaseItems=databaseItems.filter(item=>String(item.drive_letter||'').toUpperCase()==='E'||String(item.path||'').toUpperCase().startsWith('E:'));
  const changed=databaseItems.filter(item=>Number(item.file_modified_at)!==Number(item.imported_modified_at)||Number(item.file_size)!==Number(item.imported_size));
  const candidateTotal=marked.length+approved.length;
  cards.innerHTML=`<article class="metric-card"><span>Database VDJ</span><b>${changed.length}</b><small class="muted-label">da aggiornare su ${databaseItems.length}</small></article><article class="metric-card"><span>Libreria definitiva E:</span><b>${Number(stats.tracks_e||0).toLocaleString('it-IT')}</b><small class="muted-label">unica libreria KR Desk</small></article><article class="metric-card"><span>Doppioni E:</span><b>${Number(stats.duplicates||0).toLocaleString('it-IT')}</b><small class="muted-label">gruppi interni alla definitiva</small></article><article class="metric-card"><span>Richieste aperte</span><b>${Number(stats.requests||0).toLocaleString('it-IT')}</b><small class="muted-label">nuove dal pubblico</small></article><article class="metric-card"><span>Candidati cancellazione</span><b>${candidateTotal.toLocaleString('it-IT')}</b><small class="muted-label">${marked.length} marcati · ${approved.length} approvati</small></article>`;
  const issueTarget=$('#studio-issue-cards');
  if(issueTarget&&issues){const definitions=[
    ['below_standard','Audio sotto standard','MP3 sotto 320 / formati da valutare',{quality:'below'}],
    ['no_spotify_id','Senza Spotify ID','da agganciare a Spotify',{spotify_state:'no_id'}],
    ['missing_metrics','Metriche mancanti','ID presente ma dati non caricati',{spotify_state:'missing_metrics'}],
    ['missing_genre','Senza genere','classificazione incompleta',{missing:'genre'}],
    ['missing_year','Senza anno','utile per epoca e playlist',{missing:'year'}],
    ['missing_key','Senza key','non sicuri per Camelot',{missing:'key'}],
  ];issueTarget.innerHTML=definitions.map(([key,label,note,filters])=>`<button type="button" class="studio-issue-card" data-studio-filters="${escapeHtml(JSON.stringify(filters))}"><strong>${Number(issues[key]||0).toLocaleString('it-IT')}</strong><span>${label}</span><small>${note}</small></button>`).join('')}

  const target=$('#studio-database-summary');
  if(target)target.innerHTML=databaseItems.length?databaseItems.map(item=>{const itemChanged=changed.includes(item);return `<div class="compact-row"><span class="number ${itemChanged?'warn':''}">${itemChanged?'!':'OK'}</span><div><strong>${escapeHtml(item.label)}</strong><small>${escapeHtml(item.path)}</small></div><span class="badge ${itemChanged?'amber':''}">${itemChanged?'Da aggiornare':'OK'}</span></div>`}).join(''):'<div class="empty-state">Nessun database VirtualDJ rilevato.</div>';
  if(scan&&scan.status)$('#studio-database-summary')?.insertAdjacentHTML('beforeend',`<div class="compact-row"><span class="number">E</span><div><strong>Ultimo controllo E</strong><small>${Number(scan.files_scanned||0).toLocaleString('it-IT')} file ? ${escapeHtml(scan.completed_at||scan.started_at||'')}</small></div><span class="badge">${escapeHtml(scan.status)}</span></div>`);
}

async function refreshLive(){try{const live=await api('live');state.bootstrap.current=live.current;state.bootstrap.recent=live.recent;state.bootstrap.session_started_at=live.started_at;state.bootstrap.stats.played_today=live.total;state.bootstrap.stats.requests=live.requests;renderDashboard(false)}catch(error){}}
async function savePendingLiveTags(){const pending=state.pendingLiveTags;if(!pending)return;await post('track-update',pending);state.pendingLiveTags=null}
async function refreshLiveCard(){try{const previousId=Number(state.bootstrap?.current?.id||0);const live=await api('live');const nextId=Number(live.current?.id||0);if(nextId!==previousId)await savePendingLiveTags();if(nextId===previousId&&state.pendingLiveTags)live.current.tags=[...state.pendingLiveTags.tags];state.bootstrap.current=live.current;renderCurrent(live.current);if(nextId!==previousId)window.dispatchEvent(new CustomEvent('vdj-live-track-change',{detail:live.current}))}catch(error){toast(error.message)}}
function renderCurrent(track){const target=$('#current-track');target.classList.remove('skeleton');if(!track){target.innerHTML='<div class="empty-state">Segna un brano come suonato per iniziare.</div>';return}const manualTags=Array.isArray(track.tags)?track.tags:[];const automaticTags=Array.isArray(track.auto_tags)?track.auto_tags:[];const automaticCatalog=['PISTA','ALTA ENERGIA','CANTO','PICCO','RECUPERO PISTA','SUCCESSO','POPOLARE','REGGAETON','DEMBOW','BACHATA','SALSA','TIMBA','CUBATON','URBAN','EDM'];const allTags=state.bootstrap?.tags||[];target.innerHTML=`<div class="cover">${escapeHtml((track.artist||'KR').slice(0,2).toUpperCase())}</div><div class="track-main"><h2>${escapeHtml(track.title)}</h2><p>${escapeHtml(track.artist)}</p><div class="track-meta"><span>BPM<b>${track.bpm??'-'}</b></span><span>KEY<b>${escapeHtml(track.camelot||track.musical_key||'-')}</b></span><span>SCALA<b>${scaleMode(track)}</b></span><span>GENERE<b>${escapeHtml(track.genre||'-')}</b></span></div></div><div class="live-auto-tags">${automaticCatalog.map(tag=>`<span class="${automaticTags.includes(tag)?'active':''}">${escapeHtml(tag)}</span>`).join('')}</div><div><div class="energy-bars">${[1,2,3,4,5].map(i=>`<i class="${i<=track.energy?'on':''}"></i>`).join('')}</div><span class="cell-label">ENERGIA ${track.energy}/5</span></div><div class="live-tag-panel"><span class="cell-label">TAG DJ - CLICCA PER AGGIUNGERE O TOGLIERE</span><div class="live-tag-picker" data-track-id="${track.id}">${allTags.map(tag=>`<button type="button" class="live-tag ${manualTags.includes(tag)?'active':''}" data-tag="${escapeHtml(tag)}">${escapeHtml(tag)}</button>`).join('')}</div></div>`}
async function loadDashboardRequests(){const data=await api('requests');const items=data.items.filter(item=>item.status==='new').slice(0,4);$('#dashboard-requests').innerHTML=items.length?items.map(item=>`<div class="compact-row"><span class="number">◎</span><div><strong>${escapeHtml(item.query)}</strong><small>${escapeHtml(item.guest_name||'Anonimo')}</small></div><span class="badge amber">Nuova</span></div>`).join(''):'<div class="empty-state">Nessuna richiesta in attesa</div>'}
function updateClock(){const now=new Date();$('#clock').textContent=now.toLocaleTimeString('it-IT',{hour:'2-digit',minute:'2-digit'});const start=new Date((state.bootstrap?.session_started_at||state.bootstrap?.settings.event_started_at||'').replace(' ','T'));if(!Number.isNaN(start.getTime())){const elapsed=Math.max(0,Math.floor((now-start)/1000));$('#session-timer').textContent=[Math.floor(elapsed/3600),Math.floor(elapsed%3600/60),elapsed%60].map(value=>String(value).padStart(2,'0')).join(':')}}

async function loadTracks(silent=false){const params=new URLSearchParams({q:$('#library-search')?.value||'',bpm:$('#filter-bpm')?.value||'',musical_key:$('#filter-key')?.value||'',genre:$('#filter-genre')?.value||'',year:$('#filter-year')?.value||'',limit:'120'});const data=await api(`tracks&${params}`);state.tracks=data.items;renderTracks();fillTrackSelect();if(!silent)showView('library')}
function renderTracks(){
  const target=$('#library-results');
  const replacement=window.playlistReplacementContext;
  $('#results-count').textContent=`${state.tracks.length} risultati`;
  const banner=replacement?`<div class="panel playlist-replace-banner"><strong>Sostituzione playlist attiva</strong><span>Stai scegliendo il nuovo file per: ${escapeHtml(replacement.label)}</span><button type="button" class="button ghost" id="cancel-playlist-replace">Annulla</button></div>`:'';
  target.innerHTML=banner+(state.tracks.length?state.tracks.map(track=>`<article class="track-row" data-id="${track.id}"><div class="track-identity"><strong>${escapeHtml(track.artist||'Artista sconosciuto')} - ${escapeHtml(track.title||'Titolo sconosciuto')}</strong><small title="${escapeHtml(track.file_path)}">${escapeHtml(track.file_path)}</small></div><div><span class="cell-label">BPM</span><span class="cell-value">${track.bpm??'-'}</span></div><div><span class="cell-label">KEY / SCALA</span><span class="cell-value">${escapeHtml(track.camelot||track.musical_key||'-')} | ${scaleMode(track)}</span></div><div class="hide-mobile"><span class="cell-label">DURATA</span><span class="cell-value">${formatDuration(track.duration)}</span></div><div class="hide-tablet hide-mobile"><span class="cell-label">GENERE / ANNO</span><span class="cell-value">${escapeHtml(track.genre||'-')} | ${track.year||'-'}</span></div><div class="track-tags hide-mobile">${track.version?`<span class="badge blue">${escapeHtml(track.version)}</span>`:''}${(track.tags||[]).slice(0,2).map(tag=>`<span class="badge">${escapeHtml(tag)}</span>`).join('')}</div><div class="track-actions">${replacement?'<button class="button accent" data-action="playlist-replace">Usa per playlist</button>':''}<button class="more-button">...</button><div class="action-menu"><button data-action="edit">Tag e punteggi</button><button data-action="played">Segna come suonato</button><button data-action="queue">Aggiungi ad Automix</button></div></div></article>`).join(''):'<div class="empty-state">Nessun brano trovato. Prova altri filtri.</div>');
}
function fillTrackSelect(){const select=$('#current-track-select');if(!select)return;const currentTrack=state.bootstrap?.suggestion_start||state.bootstrap?.current;const current=currentTrack?.id;const options=[...state.tracks];if(current&& !options.some(track=>Number(track.id)===Number(current)))options.unshift(currentTrack);select.innerHTML=options.map(track=>`<option value="${track.id}" ${track.id==current?'selected':''}>${escapeHtml(track.artist)} - ${escapeHtml(track.title)}</option>`).join('')}
async function loadSuggestions(mode=state.currentMode){state.currentMode=mode;const id=Number($('#current-track-select').value||state.bootstrap?.current?.id||state.tracks[0]?.id);if(!id)return;$('#suggestions-list').innerHTML='<div class="empty-state">Analisi compatibilit? in corso...</div>';const data=await api(`suggestions&current_id=${id}&mode=${encodeURIComponent(mode)}`);$('#suggestions-list').innerHTML=data.items.length?data.items.map((track,index)=>`<article class="suggestion-card"><span class="rank">${String(index+1).padStart(2,'0')}</span><div class="track-identity"><strong>${escapeHtml(track.artist)} - ${escapeHtml(track.title)}</strong><small>${escapeHtml(track.genre||'-')} | ${track.energy}/5 energia</small></div><div class="mobile-hidden"><span class="cell-label">BPM</span><b>${track.bpm??'-'}</b></div><div class="mobile-hidden"><span class="cell-label">KEY</span><b>${escapeHtml(track.camelot||track.musical_key||'-')}</b></div><div class="suggestion-reason mobile-hidden"><b>${track.score}% compatibile</b>${escapeHtml(track.reasons.join(' | '))}</div><div><div class="suggestion-badges">${track.badges.map(badge=>`<span class="badge">${escapeHtml(badge)}</span>`).join('')}</div><button class="button ghost suggestion-play" data-id="${track.id}">Segna suonato</button></div></article>`).join(''):'<div class="empty-state">Nessuna proposta: riduci esclusione brani recenti nelle impostazioni.</div>'}
async function loadDuplicates(){const data=await api('duplicates');const labels={missing_metadata:'Metadati mancanti',missing_analysis:'Senza BPM / key',missing_files:'File non trovati',low_quality:'Qualità sospetta',dirty_titles:'Titoli sporchi'};$('#issue-cards').innerHTML=Object.entries(data.issues).map(([key,value])=>`<article class="metric-card"><span>${labels[key]}</span><b>${value}</b><small class="muted-label">BRANI</small></article>`).join('');$('#duplicates-list').innerHTML=data.groups.length?data.groups.map(group=>`<article class="duplicate-group"><div class="duplicate-head"><div><strong>${escapeHtml(group.label)}</strong><p>${escapeHtml(group.reason)}</p></div><div class="duplicate-actions"><button class="button accent duplicate-decision" data-fingerprint="${group.fingerprint}" data-decision="keep">Mantieni consigliato</button><button class="button ghost duplicate-decision" data-fingerprint="${group.fingerprint}" data-decision="ignore">Ignora gruppo</button></div></div><div class="duplicate-files">${group.items.map((track,index)=>`<div class="duplicate-file"><span>${index===0?'★':'○'}</span><div><strong>${escapeHtml(track.file_name)}</strong><small>${escapeHtml(track.file_path)}</small></div><span>${track.bitrate?track.bitrate+' kbps':'—'}</span><span class="hide-mobile">${track.file_exists?'Presente':'Mancante'}</span></div>`).join('')}</div></article>`).join(''):'<div class="empty-state panel">Nessun doppione normalizzato rilevato.</div>'}

async function loadRequests(){const data=await api('requests');let items=data.items;if(state.requestFilter!=='all')items=items.filter(item=>item.status===state.requestFilter);const labels={new:'Nuova',approved:'Approvata',rejected:'Rifiutata',next:'Dopo',queued:'Automix',played:'Già suonata'};$('#requests-list').innerHTML=items.length?items.map(item=>`<article class="request-card"><div><span class="badge ${item.status==='new'?'amber':''}">${labels[item.status]||item.status}</span><h3>${escapeHtml(item.query)}</h3><p>Richiesta da ${escapeHtml(item.guest_name||'Anonimo')} · ${new Date(item.created_at.replace(' ','T')).toLocaleTimeString('it-IT',{hour:'2-digit',minute:'2-digit'})}</p></div><div>${item.track_id?`<strong>${escapeHtml(item.artist)} — ${escapeHtml(item.title)}</strong><p>Presente in libreria</p>`:'<span class="badge red">Non abbinata</span><p>Cerca una possibile alternativa</p>'}</div><div class="request-actions"><button class="button accent request-action" data-id="${item.id}" data-track="${item.track_id||''}" data-status="approved">Approva</button><button class="button primary request-action" data-id="${item.id}" data-track="${item.track_id||''}" data-status="queued">Automix</button><button class="button ghost request-action" data-id="${item.id}" data-track="${item.track_id||''}" data-status="next">Metti dopo</button><button class="button ghost request-action" data-id="${item.id}" data-track="${item.track_id||''}" data-status="rejected">Rifiuta</button></div></article>`).join(''):'<div class="empty-state panel">Nessuna richiesta in questa categoria.</div>'}

function fillSettings(){const form=$('#settings-form');Object.entries(state.bootstrap.settings).forEach(([key,value])=>{if(form.elements[key])form.elements[key].value=value})}
function openEditor(track){const allTags=state.bootstrap.tags;$('#track-editor').innerHTML=`<div class="editor-head"><span class="kicker">CLASSIFICAZIONE DJ</span><h2>${escapeHtml(track.artist)} — ${escapeHtml(track.title)}</h2><p>${escapeHtml(track.file_path)}</p></div><div class="tag-picker">${allTags.map(tag=>`<button type="button" class="${track.tags.includes(tag)?'active':''}" data-tag="${escapeHtml(tag)}">${escapeHtml(tag)}</button>`).join('')}</div><div class="score-grid">${[['energy','Energia'],['singability','Cantabilità'],['danceability','Ballabilità'],['familiarity','Familiarità'],['risk','Rischio']].map(([key,label])=>`<label>${label} <span class="score-value">${track[key]}</span><input type="range" name="${key}" min="1" max="5" value="${track[key]}"></label>`).join('')}</div><div class="editor-actions"><button class="button primary" id="save-track" data-id="${track.id}">Salva classificazione</button></div>`;$('#track-dialog').showModal()}

document.addEventListener('click',event=>{const modeButton=event.target.closest('[data-desk-mode]');if(!modeButton)return;setDeskMode(modeButton.dataset.deskMode)});
document.addEventListener('click',async event=>{const cancelReplace=event.target.closest('#cancel-playlist-replace');if(cancelReplace){window.playlistReplacementContext=null;renderTracks();toast('Sostituzione playlist annullata');return}const nav=event.target.closest('[data-view], [data-view-link]');if(nav){showView(nav.dataset.view||nav.dataset.viewLink);return}const quick=event.target.closest('#quick-actions [data-mode]');if(quick){state.currentMode=quick.dataset.mode;showView('suggestions');await loadSuggestions(state.currentMode);return}const more=event.target.closest('.more-button');if(more){event.stopPropagation();const menu=more.nextElementSibling;$$('.action-menu.open').forEach(item=>item!==menu&&item.classList.remove('open'));menu.classList.toggle('open');return}else $$('.action-menu.open').forEach(menu=>menu.classList.remove('open'));const action=event.target.closest('[data-action]');if(action){const row=action.closest('.track-row');const track=state.tracks.find(item=>item.id===Number(row.dataset.id));if(action.dataset.action==='playlist-replace'){const context=window.playlistReplacementContext;if(!context||!track){toast('Nessuna sostituzione playlist attiva');return}if(!window.confirm(`Sostituire nella playlist?\n\nDA: ${context.old_path}\n\nA: ${track.file_path}`))return;const result=await post('playlist-replace-track',{file:context.file,old_path:context.old_path,new_path:track.file_path});const playlistFile=context.file;window.playlistReplacementContext=null;toast(`${result.replaced} riferimento playlist sostituito`);showView('playlists');if(typeof openPlaylist==='function')await openPlaylist(playlistFile);return}if(action.dataset.action==='spotify'){const query=[track.artist,track.title].filter(Boolean).join(' ');window.open(`https://open.spotify.com/search/${encodeURIComponent(query)}`,'_blank','noopener')}if(action.dataset.action==='edit')openEditor(track);if(action.dataset.action==='played'){await post('played',{id:track.id});toast('Brano segnato come suonato');await refreshBootstrap()}if(action.dataset.action==='suggest'){state.currentMode='same';showView('suggestions');$('#current-track-select').value=track.id;await loadSuggestions()}if(action.dataset.action==='queue'){await post('queue',{id:track.id});toast('Aggiunto ad Automix')}if(action.dataset.action==='copy'){await navigator.clipboard.writeText(track.file_path);toast('Percorso copiato')}if(action.dataset.action==='folder'){await navigator.clipboard.writeText(track.folder);toast('Cartella copiata: aprila da Esplora file')}if(action.dataset.action==='duplicates'){showView('duplicates')}return}const tag=event.target.closest('.tag-picker button');if(tag){tag.classList.toggle('active');return}const save=event.target.closest('#save-track');if(save){const editor=$('#track-editor');const payload={id:Number(save.dataset.id),tags:$$('.tag-picker button.active',editor).map(item=>item.dataset.tag)};$$('input[type=range]',editor).forEach(input=>payload[input.name]=Number(input.value));await post('track-update',payload);$('#track-dialog').close();toast('Tag e punteggi aggiornati');await loadTracks(true);return}const suggestion=event.target.closest('.suggestion-play');if(suggestion){await post('played',{id:Number(suggestion.dataset.id)});toast('Brano segnato come suonato');await refreshBootstrap();return}const decision=event.target.closest('.duplicate-decision');if(decision){await post('duplicate-decision',{fingerprint:decision.dataset.fingerprint,decision:decision.dataset.decision});decision.closest('.duplicate-group').remove();toast('Decisione salvata');return}const requestAction=event.target.closest('.request-action');if(requestAction){await post('request-update',{id:Number(requestAction.dataset.id),track_id:Number(requestAction.dataset.track)||null,status:requestAction.dataset.status});toast('Richiesta aggiornata');await loadRequests();await refreshBootstrap();return}});
