loadRequests=async function(){const data=await api('requests');let items=data.items;if(state.requestFilter!=='all')items=items.filter(item=>item.status===state.requestFilter);const labels={new:'Nuova',approved:'Approvata',rejected:'Rifiutata',next:'Dopo',queued:'Automix',played:'Già suonata'};const estimate=item=>item.estimated_play_at?`<p><b>Orario stimato del brano: ${new Date(item.estimated_play_at.replace(' ','T')).toLocaleTimeString('it-IT',{hour:'2-digit',minute:'2-digit'})}</b></p>`:'';$('#requests-list').innerHTML=items.length?items.map(item=>`<article class="request-card"><div><span class="badge ${item.status==='new'?'amber':''}">${labels[item.status]||item.status}</span><h3>${escapeHtml(item.query)}</h3><p>Richiesta da ${escapeHtml(item.guest_name||'Anonimo')} · ${new Date(item.created_at.replace(' ','T')).toLocaleTimeString('it-IT',{hour:'2-digit',minute:'2-digit'})}</p>${estimate(item)}${item.note?`<p>Nota DJ: ${escapeHtml(item.note)}</p>`:''}</div><div>${item.track_id?`<strong>${escapeHtml(item.artist)} — ${escapeHtml(item.title)}</strong><p>Presente in libreria</p>`:'<span class="badge red">Non abbinata</span><p>Puoi cercare un’alternativa nella libreria</p>'}</div><div class="request-actions"><button class="button accent request-action" data-id="${item.id}" data-track="${item.track_id||''}" data-status="approved">Approva</button><button class="button primary request-action" data-id="${item.id}" data-track="${item.track_id||''}" data-status="queued">Automix</button><button class="button ghost request-action" data-id="${item.id}" data-track="${item.track_id||''}" data-status="next">Metti dopo</button><button class="button ghost request-search" data-query="${escapeHtml(item.query)}">Alternativa</button><button class="button ghost request-note" data-id="${item.id}" data-track="${item.track_id||''}" data-status="${item.status}">Nota</button><button class="button ghost request-played" data-id="${item.id}" data-track="${item.track_id||''}">Già suonato</button><button class="button ghost request-action" data-id="${item.id}" data-track="${item.track_id||''}" data-status="rejected">Rifiuta</button></div></article>`).join(''):'<div class="empty-state panel">Nessuna richiesta in questa categoria.</div>'};

const requestListObserver=new MutationObserver(()=>{$$('#requests-list .request-card').forEach(card=>{const actions=card.querySelector('.request-actions');const source=actions?.querySelector('[data-id]');if(actions&&source&&!actions.querySelector('.request-delete'))actions.insertAdjacentHTML('beforeend',`<button class="button ghost request-delete" data-id="${source.dataset.id}">Elimina</button>`)})});requestListObserver.observe($('#requests-list'),{childList:true});
document.addEventListener('click',async event=>{const button=event.target.closest('.request-delete');if(!button)return;if(!window.confirm('Eliminare definitivamente questa richiesta?'))return;await post('request-delete',{id:Number(button.dataset.id)});toast('Richiesta eliminata');await loadRequests();await refreshBootstrap()});
document.addEventListener('click',async event=>{const folder=event.target.closest('[data-action="folder"]');if(folder){const id=Number(folder.closest('.track-row').dataset.id);await post('open-folder',{id});toast('Cartella aperta sul PC DJ')}const search=event.target.closest('.request-search');if(search){$('#library-search').value=search.dataset.query;showView('library');await loadTracks()}const note=event.target.closest('.request-note');if(note){const value=window.prompt('Nota breve per la richiesta:','');if(value!==null){await post('request-update',{id:Number(note.dataset.id),track_id:Number(note.dataset.track)||null,status:note.dataset.status,note:value});toast('Nota salvata');await loadRequests()}}const played=event.target.closest('.request-played');if(played){const trackId=Number(played.dataset.track)||null;if(trackId)await post('played',{id:trackId});await post('request-update',{id:Number(played.dataset.id),track_id:trackId,status:'played'});toast('Richiesta segnata come già suonata');await loadRequests();await refreshBootstrap()}});

async function loadDatabaseStatus(){const target=$('#database-status');if(!target)return;const data=await api('database-status');const changedItems=data.items.filter(item=>Number(item.file_modified_at)!==Number(item.imported_modified_at)||Number(item.file_size)!==Number(item.imported_size));target.innerHTML=data.items.map(item=>{const changed=changedItems.includes(item);const status=item.status==='synced'&&!changed?'Aggiornato':changed?'Da aggiornare':item.status==='unchanged'?'Aggiornato':item.status;return `<div class="database-row"><span class="database-dot ${changed?'pending':'ok'}"></span><div><strong>${escapeHtml(item.label)}</strong><small>${escapeHtml(item.path)}</small></div><div><span class="cell-label">MODIFICATO</span><b>${escapeHtml(item.file_modified_label||'—')}</b></div><div><span class="cell-label">BRANI</span><b>${Number(item.record_count||0).toLocaleString('it-IT')}</b></div><span class="badge ${changed?'amber':''}">${escapeHtml(status)}</span></div>`}).join('')||'<div class="empty-state">Nessun database VirtualDJ rilevato.</div>';if(changedItems.length&&!state.databaseWarningShown){state.databaseWarningShown=true;toast(`${changedItems.length} database VirtualDJ da aggiornare`)}}


async function syncAllDatabases(force=false,silent=false,button=null){
  const targetButton=button||$('#sync-all-vdj');
  const previous=targetButton?.innerHTML;
  if(targetButton)targetButton.disabled=true;
  if(!silent)krProgress.start('Sincronizzazione database VDJ',0,'Controllo date modifica');
  try{
    if(!silent)krProgress.update('Sincronizzazione database VDJ',0,0,'Lettura database VirtualDJ');
    const result=await post('sync-all',{force});
    const total=Number(result.total||result.databases?.length||0);
    const changed=Number(result.changed||0);
    if(!silent)krProgress.done('Sincronizzazione VDJ completata',`${changed} database aggiornati su ${total}`);
    if(!silent)toast(`${changed} database VDJ aggiornati su ${total}`);
    await loadDatabaseStatus();
    await refreshBootstrap();
    if(typeof loadStudioDashboard==='function'&&$('#view-studio-dashboard')?.classList.contains('active'))await loadStudioDashboard();
    return result;
  }catch(error){
    if(!silent)krProgress.fail('Sincronizzazione VDJ fallita',error.message);
    if(!silent)toast(error.message);
    throw error;
  }finally{
    if(targetButton){targetButton.disabled=false;targetButton.innerHTML=previous}
  }
}
window.syncAllDatabases=syncAllDatabases;

async function reconcileDatabases(button=null){
  const targetButton=button||$('#reconcile-vdj');
  const previous=targetButton?.innerHTML;
  if(targetButton)targetButton.disabled=true;
  krProgress.start('Riconciliazione database VDJ',0,'Forzo sync e riallineo collegamenti');
  try{
    const result=await post('reconcile-vdj',{});
    const linked=Number(result.linked||0);
    const removed=Number(result.removed||0);
    krProgress.done('Riconciliazione VDJ completata',`${linked} collegati - ${removed} orfani rimossi`);
    toast(`Riconciliazione completata: ${linked} collegati - ${removed} orfani rimossi`);
    await loadDatabaseStatus();
    await refreshBootstrap();
    await loadTracks(true,false);
    if(typeof loadStudioDashboard==='function'&&$('#view-studio-dashboard')?.classList.contains('active'))await loadStudioDashboard();
    return result;
  }catch(error){
    krProgress.fail('Riconciliazione VDJ fallita',error.message);
    toast(error.message);
    throw error;
  }finally{
    if(targetButton){targetButton.disabled=false;targetButton.innerHTML=previous}
  }
}
window.reconcileDatabases=reconcileDatabases;

async function loadMusicRoots(){
  const rootsData=await api('music-roots');
  const current=state.bootstrap?.settings.music_root||'';
  const settingsSelect=$('#music-root-select');
  const hasCurrent=rootsData.items.some(item=>item.path.toLowerCase()===current.toLowerCase());
  if(settingsSelect)settingsSelect.innerHTML=(!hasCurrent?'<option value="" selected>Seleziona una cartella musicale</option>':'')+(rootsData.items.map(item=>`<option value="${escapeHtml(item.path)}" ${item.path.toLowerCase()===current.toLowerCase()?'selected':''}>${escapeHtml(item.label)}</option>`).join('')||'<option value="">Nessuna cartella musicale rilevata</option>');
  const filterSelect=$('#filter-folder');
  const duplicateSelect=$('#duplicate-folder');
  if(filterSelect){
    const selected=filterSelect.value;
    const groups=new Map();
    for(const item of rootsData.items){const root=item.root||item.path;if(!groups.has(root))groups.set(root,[]);groups.get(root).push(item)}
    filterSelect.innerHTML='<option value="">Tutta la libreria</option>'+[...groups.entries()].map(([root,items])=>`<optgroup label="${escapeHtml(root)}">${items.map(item=>`<option value="${escapeHtml(item.path)}">${escapeHtml(item.label)}</option>`).join('')}</optgroup>`).join('');
    if(selected&&rootsData.items.some(item=>item.path===selected))filterSelect.value=selected;
    $('#expand-folder-tracks')?.classList.toggle('hidden',!filterSelect.value);
  }
  if(duplicateSelect)await loadDuplicateFolders();
}
loadTracks=async function(silent=false,append=false){if(state.libraryLoading)return;state.libraryLoading=true;const button=$('#load-more-tracks');if(button)button.disabled=true;try{const offset=append?state.tracks.length:0;const params=new URLSearchParams({q:$('#library-search')?.value.trim()||'',bpm:$('#filter-bpm')?.value||'',musical_key:$('#filter-key')?.value||'',genre:$('#filter-genre')?.value||'',year:$('#filter-year')?.value||'',folder_root:$('#filter-folder')?.value||'',...(state.libraryExtraFilters||{}),limit:'60',offset:String(offset)});const data=await api(`tracks&${params}`);state.tracks=append?[...state.tracks,...data.items]:data.items;state.libraryTotal=data.total;renderTracks();fillTrackSelect();$('#results-count').textContent=`${state.tracks.length.toLocaleString('it-IT')} di ${data.total.toLocaleString('it-IT')}`;const query=$('#library-search')?.value.trim();const folder=$('#filter-folder');const activeIssue=Object.keys(state.libraryExtraFilters||{}).length?' - filtro Studio':'';$('#results-title').textContent=query?`Risultati per ${query}${activeIssue}`:folder?.value?folder.options[folder.selectedIndex].text:`Tutti i brani${activeIssue}`;$('#expand-folder-tracks')?.classList.toggle('hidden',!folder?.value);button.classList.toggle('hidden',!data.has_more);if(!silent)showView('library')}finally{state.libraryLoading=false;if(button)button.disabled=false}}
$('#filter-folder').addEventListener('change',()=>loadTracks(false,false));
$('#music-root-select').addEventListener('change',async event=>{const path=event.target.value;await post('settings',{music_root:path});await loadMusicRoots();$('#filter-folder').value=path;showView('library');await loadTracks(true,false)});
$('#load-more-tracks').addEventListener('click',()=>loadTracks(true,true));
let librarySearchTimer;$('#library-search').addEventListener('input',()=>{clearTimeout(librarySearchTimer);librarySearchTimer=setTimeout(()=>loadTracks(true,false),300)});
setTimeout(async()=>{await loadMusicRoots();await loadDatabaseStatus()},800);

loadDuplicates=async function(){const target=$('#duplicates-list');target.innerHTML='<div class="empty-state panel">Lettura archivio controllo E:…</div>';const data=await api('e-duplicates&limit=100');const scan=data.scan;if(!scan){$('#issue-cards').innerHTML='';target.innerHTML='<div class="empty-state panel">Nessun controllo ancora eseguito. Premi “Avvia controllo E:”.</div>';return}$('#issue-cards').innerHTML=`<article class="metric-card"><span>File analizzati su E:</span><b>${Number(scan.files_scanned).toLocaleString('it-IT')}</b></article><article class="metric-card"><span>Impronte coincidenti</span><b>${Number(scan.exact_groups).toLocaleString('it-IT')}</b></article><article class="metric-card"><span>Artista/titolo simili</span><b>${Number(scan.normalized_groups).toLocaleString('it-IT')}</b></article><article class="metric-card"><span>Stato procedura</span><b class="scan-status">${escapeHtml(scan.status)}</b><span>${escapeHtml(scan.completed_at||scan.started_at)}</span></article>`;target.innerHTML=data.items.length?data.items.map(group=>`<article class="duplicate-group"><div class="duplicate-head"><div><span class="badge ${group.type==='exact'?'red':'amber'}">${group.type==='exact'?'Impronta uguale':'Artista + titolo'}</span><strong>${escapeHtml(group.label)}</strong><p>${escapeHtml(group.reason)}</p></div><div class="duplicate-actions"><button class="button accent e-duplicate-decision" data-id="${group.id}" data-decision="keep_recommended">Mantieni consigliato</button><button class="button ghost e-duplicate-decision" data-id="${group.id}" data-decision="ignore">Ignora</button></div></div><div class="duplicate-files">${group.items.map(item=>`<div class="duplicate-file"><span>${Number(item.is_recommended)?'★':'○'}</span><div><strong>${escapeHtml(item.file_name)}</strong><small>${escapeHtml(item.file_path)}</small></div><span>${item.bitrate?item.bitrate+' kbps':(Number(item.file_size)/1048576).toFixed(1)+' MB'}</span><span class="hide-mobile">${escapeHtml(item.version||item.extension.toUpperCase())}</span></div>`).join('')}</div></article>`).join(''):'<div class="empty-state panel">Nessun doppione rilevato su E:.</div>';if(data.has_more)target.insertAdjacentHTML('beforeend',`<div class="empty-state">Mostrati i primi 100 gruppi su ${data.total.toLocaleString('it-IT')}.</div>`)};

$('#scan-e-duplicates').addEventListener('click',async event=>{const button=event.currentTarget;button.disabled=true;button.textContent='Controllo in corso…';try{const result=await post('e-duplicates-scan',{});toast(`Controllo completato: ${Number(result.files_scanned).toLocaleString('it-IT')} file`);await loadDuplicates()}catch(error){toast(error.message)}finally{button.disabled=false;button.textContent='Avvia controllo E:'}});
document.addEventListener('click',async event=>{const decision=event.target.closest('.e-duplicate-decision');if(!decision)return;await post('e-duplicates-decision',{id:Number(decision.dataset.id),decision:decision.dataset.decision});decision.closest('.duplicate-group').remove();toast('Decisione salvata nell’archivio E:')});

async function loadDuplicateFolders(){const select=$('#duplicate-folder');if(!select)return;const selected=select.value;const data=await api('comparison-folders');const desktopPrefix='c:\\users\\fabbr\\desktop\\';const options=[{path:'E:\\',label:'E: · Tutto il drive',root:'E:\\',depth:0},...data.items].filter(item=>item.path.toLowerCase().startsWith(desktopPrefix)||/^e:\\/i.test(item.path));const groups=new Map();const seen=new Set();for(const item of options){const key=item.path.toLowerCase();if(seen.has(key))continue;seen.add(key);const root=item.root||item.path;if(!groups.has(root))groups.set(root,[]);groups.get(root).push(item)}select.innerHTML='<option value="">Scegli una cartella…</option>'+[...groups.entries()].map(([root,items])=>`<optgroup label="${escapeHtml(root)}">${items.map(item=>`<option value="${escapeHtml(item.path)}">${item.depth?'↳ '.repeat(Math.min(Number(item.depth),3)):''}${escapeHtml(item.label)}</option>`).join('')}</optgroup>`).join('');if(selected&&seen.has(selected.toLowerCase()))select.value=selected}

loadDuplicates=async function(){
  const folder=$('#duplicate-folder')?.value||'';
  const target=$('#duplicates-list');
  if(!folder){
    $('#issue-cards').innerHTML='';
    $('#duplicate-results-title').textContent='Risultati della cartella';
    target.innerHTML='<div class="empty-state panel">Scegli una cartella E: per avviare un controllo mirato.</div>';
    return;
  }
  if(!folder.toUpperCase().startsWith('E:\\')){
    $('#issue-cards').innerHTML='';
    $('#duplicate-results-title').textContent='Solo libreria definitiva';
    target.innerHTML='<div class="empty-state panel">KR Desk lavora solo sulla libreria definitiva E:.</div>';
    return;
  }
  target.innerHTML='<div class="empty-state panel">Lettura risultati?</div>';
  const data=await api(`e-duplicates&limit=100&folder_root=${encodeURIComponent(folder)}`);
  const scan=data.scan;
  $('#duplicate-results-title').textContent=`Doppioni interni ? ${folder}`;
  $('#issue-cards').innerHTML=`<article class="metric-card"><span>File inventariati su E:</span><b>${Number(scan?.files_scanned||0).toLocaleString('it-IT')}</b></article><article class="metric-card"><span>Gruppi nella cartella</span><b>${Number(data.total).toLocaleString('it-IT')}</b></article><article class="metric-card"><span>Regola</span><b>Nessuna cancellazione</b><span>Revisione manuale</span></article>`;
  target.innerHTML=data.items.length?data.items.map(group=>`<article class="duplicate-group"><div class="duplicate-head"><div><span class="badge ${group.type==='exact'?'red':'amber'}">${group.type==='exact'?'Impronta uguale':'Artista + titolo'}</span><strong>${escapeHtml(group.label)}</strong><p>${escapeHtml(group.reason)}</p></div><div class="duplicate-actions"><button class="button accent e-duplicate-decision" data-id="${group.id}" data-decision="keep_recommended">Mantieni consigliato</button><button class="button ghost e-duplicate-decision" data-id="${group.id}" data-decision="ignore">Ignora</button></div></div><div class="duplicate-files">${group.items.map(item=>`<div class="duplicate-file"><span>${Number(item.is_recommended)?'?':'?'}</span><div><strong>${escapeHtml(item.file_name)}</strong><small>${escapeHtml(item.file_path)}</small></div><span>${(Number(item.file_size)/1048576).toFixed(1)} MB</span><span class="hide-mobile">${escapeHtml(item.version||item.extension.toUpperCase())}</span></div>`).join('')}</div></article>`).join(''):'<div class="empty-state panel">Nessun doppione interno rilevato nella cartella scelta.</div>';
}
const previousScanButton=$('#scan-e-duplicates');const scanButton=previousScanButton.cloneNode(true);previousScanButton.replaceWith(scanButton);scanButton.addEventListener('click',async()=>{const folder=$('#duplicate-folder').value;if(!folder){toast('Scegli prima una cartella');return}scanButton.disabled=true;scanButton.textContent='Controllo in corso…';try{if(!folder.toUpperCase().startsWith('E:\\')){toast('KR Desk lavora solo sulla libreria definitiva E:');return}const result=await post('e-duplicates-scan',{});toast(`Inventario E aggiornato: ${Number(result.files_scanned).toLocaleString('it-IT')} file`);await loadDuplicates()}catch(error){toast(error.message);await loadDuplicateFolders();await loadDuplicates()}finally{scanButton.disabled=false;scanButton.textContent='Controlla cartella'}});
$('#duplicate-folder').addEventListener('change',loadDuplicates);
document.addEventListener('click',async event=>{const button=event.target.closest('.candidate-decision');if(!button)return;await post('deletion-candidate-decision',{id:Number(button.dataset.id),status:button.dataset.status});toast('Stato candidato aggiornato');await loadDuplicates()});
setTimeout(loadDuplicateFolders,900);

function renderCandidateArchive(items,title='Archivio marcati'){$('#duplicate-results-title').textContent=title;$('#issue-cards').innerHTML=`<article class="metric-card"><span>Brani marcati</span><b>${items.length.toLocaleString('it-IT')}</b></article><article class="metric-card"><span>Destinazione verificata</span><b>E:</b><span>Copia da conservare</span></article><article class="metric-card"><span>Operazione</span><b>In attesa</b><span>Nessun file cancellato</span></article>`;$('#duplicates-list').innerHTML=items.length?items.map(item=>`<article class="duplicate-group"><div class="duplicate-head"><div><span class="badge ${item.match_type==='exact'?'red':'amber'}">${item.match_type==='exact'?'Impronta uguale':'Artista + titolo'}</span><strong>${escapeHtml(item.source_name)}</strong><p>${escapeHtml(item.reason)}</p></div><div class="duplicate-actions"><button class="button accent candidate-decision" data-id="${item.id}" data-status="approved">Approva candidato</button><button class="button ghost candidate-decision" data-id="${item.id}" data-status="ignored">Ignora</button></div></div><div class="duplicate-files"><div class="duplicate-file"><span>×</span><div><strong>File marcato</strong><small>${escapeHtml(item.source_path)}</small></div><span>${(Number(item.source_size)/1048576).toFixed(1)} MB</span><span class="badge red">${escapeHtml(item.status)}</span></div><div class="duplicate-file"><span>★</span><div><strong>Copia da conservare su E:</strong><small>${escapeHtml(item.e_file_path)}</small></div><span>${(Number(item.e_file_size)/1048576).toFixed(1)} MB</span><span class="badge">Conserva</span></div></div></article>`).join(''):'<div class="empty-state panel">Nessun brano marcato per la cancellazione.</div>'}

function renderApprovedArchive(items,folders=[],currentFolder=''){const total=folders.reduce((sum,folder)=>sum+Number(folder.total),0);const current=folders.find(folder=>folder.source_folder.toLowerCase()===currentFolder.toLowerCase());const currentTotal=Number(current?.total||0);$('#duplicate-results-title').textContent='Archivio approvati';$('#issue-cards').innerHTML=`<article class="metric-card"><span>Approvati totali</span><b>${total.toLocaleString('it-IT')}</b></article><article class="metric-card"><span>Approvati cartella corrente</span><b>${currentTotal.toLocaleString('it-IT')}</b><span>${escapeHtml(currentFolder||'Nessuna cartella selezionata')}</span></article><article class="metric-card"><span>Network Control</span><b>9665</b><span>Nessuna autenticazione</span></article>`;$('#duplicates-list').innerHTML=items.length?items.map(item=>`<article class="approved-file-row"><div><span class="badge ${item.match_type==='exact'?'red':'amber'}">${item.match_type==='exact'?'Impronta uguale':'Artista + titolo'}</span><strong>${escapeHtml(item.source_name)}</strong><small>${escapeHtml(item.source_path)}</small></div><span>${(Number(item.source_size)/1048576).toFixed(1)} MB</span><span class="badge red">Approvato</span><div class="approved-row-actions"><button class="button accent vdj-search-candidate" data-id="${item.id}">Cerca in VDJ</button><button class="button ghost" disabled title="La cancellazione Network Control sarà collegata nel passaggio successivo">Cancella</button></div></article>`).join(''):'<div class="empty-state panel">Nessun brano approvato.</div>'}

$('#duplicate-folder').addEventListener('change',event=>{const folder=event.target.value;const button=$('#mark-all-candidates');$('#approve-all-marked').classList.add('hidden');$('#search-move-all-approved').classList.add('hidden');button.classList.toggle('hidden',!folder);button.textContent=folder.toUpperCase().startsWith('E:\\')?'Marca non consigliati':'Marcali tutti'});
$('#clear-candidate-states').addEventListener('click',async()=>{if(!window.confirm('Azzerare tutto l’archivio stati dei doppioni? Nessun file fisico sarà cancellato.'))return;const result=await post('deletion-candidates-clear',{});toast(`${Number(result.deleted).toLocaleString('it-IT')} stati eliminati`);await loadDuplicates()});
$('#mark-all-candidates').addEventListener('click',async()=>{const folder=$('#duplicate-folder').value;if(!folder)return;const internal=folder.toUpperCase().startsWith('E:\\');const result=await post(internal?'e-duplicates-mark-nonrecommended':'deletion-candidates-mark-all',{folder});toast(`${Number(result.updated).toLocaleString('it-IT')} candidati marcati`);await loadDuplicates()});
$('#show-marked-candidates').addEventListener('click',async()=>{const data=await api('deletion-candidates&status=marked');$('#mark-all-candidates').classList.add('hidden');$('#approve-all-marked').classList.toggle('hidden',data.items.length===0);renderCandidateArchive(data.items,'Marcati da approvare')});
$('#show-approved-candidates').addEventListener('click',async()=>{const [data,summary]=await Promise.all([api('deletion-candidates&status=approved'),api('approved-folder-summary')]);$('#mark-all-candidates').classList.add('hidden');$('#approve-all-marked').classList.add('hidden');$('#search-move-all-approved').classList.toggle('hidden',data.items.length===0);renderApprovedArchive(data.items,summary.items,$('#duplicate-folder').value)});
document.addEventListener('click',async event=>{const button=event.target.closest('.vdj-search-candidate');if(!button)return;button.disabled=true;try{const result=await post('vdj-search-candidate',{id:Number(button.dataset.id)});toast(`Cercato in VDJ e spostato: ${result.query}`);button.closest('.approved-file-row').remove()}catch(error){toast(error.message)}finally{button.disabled=false}});
$('#search-move-all-approved').addEventListener('click',async event=>{const button=event.currentTarget;const data=await api('deletion-candidates&status=approved');const items=data.items;if(!items.length)return;if(!window.confirm(`Cercare e spostare ${items.length} file in Da_cancellare?`))return;button.disabled=true;let moved=0;const errors=[];for(let index=0;index<items.length;index++){button.textContent=`Spostamento ${index+1}/${items.length}`;try{await post('vdj-search-candidate',{id:Number(items[index].id)});moved++;const row=$(`.vdj-search-candidate[data-id="${items[index].id}"]`)?.closest('.approved-file-row');if(row)row.remove()}catch(error){errors.push(`${items[index].source_name}: ${error.message}`)}}button.disabled=false;button.textContent='Cerca e sposta tutto';toast(`${moved} spostati${errors.length?`, ${errors.length} errori`:''}`);await $('#show-approved-candidates').click()});
$('#approve-all-marked').addEventListener('click',async()=>{const result=await post('deletion-candidates-approve-all',{});toast(`${Number(result.updated).toLocaleString('it-IT')} brani approvati`);$('#approve-all-marked').classList.add('hidden');const data=await api('deletion-candidates&status=marked');renderCandidateArchive(data.items,'Marcati da approvare')});

const candidateUiObserver=new MutationObserver(()=>{if(!$('#duplicate-results-title')?.textContent.startsWith('Confronto con E:'))return;$$('.candidate-decision[data-status="approved"]',$('#duplicates-list')).forEach(button=>{button.dataset.status='marked';button.textContent='Marca'});$$('#issue-cards .metric-card span').forEach(label=>{if(label.textContent==='Candidati archiviati')label.textContent='Corrispondenze trovate'})});candidateUiObserver.observe($('#view-duplicates'),{childList:true,subtree:true});
const obsoleteDeleteButtonObserver=new MutationObserver(()=>{$$('.approved-row-actions button:disabled',$('#duplicates-list')).forEach(button=>button.remove());$$('.vdj-search-candidate',$('#duplicates-list')).forEach(button=>{if(button.textContent!=='Cerca e sposta')button.textContent='Cerca e sposta'})});obsoleteDeleteButtonObserver.observe($('#duplicates-list'),{childList:true,subtree:true});

function currentLibraryParams(limit,offset){return new URLSearchParams({q:$('#library-search')?.value.trim()||'',bpm:$('#filter-bpm')?.value||'',musical_key:$('#filter-key')?.value||'',genre:$('#filter-genre')?.value||'',year:$('#filter-year')?.value||'',folder_root:$('#filter-folder')?.value||'',limit:String(limit),offset:String(offset)})}
async function collectCurrentLibrary(){const tracks=[];let offset=0,total=0;do{const data=await api(`tracks&${currentLibraryParams(200,offset)}`);tracks.push(...data.items);total=Number(data.total);offset=tracks.length}while(offset<total);return tracks}
$('#filter-folder').addEventListener('change',event=>$('#expand-folder-tracks').classList.toggle('hidden',!event.target.value));
$('#expand-folder-tracks').addEventListener('click',async event=>{if(!$('#filter-folder').value)return;const button=event.currentTarget;button.disabled=true;button.textContent='Espansione…';try{state.tracks=await collectCurrentLibrary();state.libraryTotal=state.tracks.length;renderTracks();fillTrackSelect();$('#results-count').textContent=`${state.tracks.length.toLocaleString('it-IT')} di ${state.tracks.length.toLocaleString('it-IT')}`;$('#load-more-tracks').classList.add('hidden');toast(`${state.tracks.length.toLocaleString('it-IT')} brani caricati`)}catch(error){toast(error.message)}finally{button.disabled=false;button.textContent='Espandi tutta la cartella'}});
$('#send-library-to-spotify').addEventListener('click',async event=>{const button=event.currentTarget;const total=Number(state.libraryTotal||state.tracks.length);if(total>500&&!window.confirm(`Caricare ${total.toLocaleString('it-IT')} brani in Spotify → VDJ?`))return;button.disabled=true;button.textContent='Caricamento…';try{const tracks=await collectCurrentLibrary();showView('spotify');const frame=$('.embedded-tool-frame');const send=()=>frame.contentWindow.postMessage({type:'vdjdesk-library',tracks},location.origin);if(frame.contentDocument?.readyState==='complete')send();else frame.addEventListener('load',send,{once:true});toast(`${tracks.length.toLocaleString('it-IT')} brani portati in Spotify → VDJ`)}catch(error){toast(error.message)}finally{button.disabled=false;button.textContent='Porta in Spotify → VDJ'}});
